  "WARNING-STR": {
   "name": "WARNING-STR",
   "kind": "global",
   "file": "island.zil",
   "line": 1817,
   "value": "\"Johnny looks around and says, \"This is no place to continue. If McGinty\nfinds out about this, we're sunk. We better meet at the lighthouse at 9:30.\nGlad you're aboard.\"\""
  },
