  "WHEEEEE": {
   "name": "WHEEEEE",
   "kind": "global",
   "file": "verbs.zil",
   "line": 1726,
   "value": "<PLTABLE \"Very good. Now you can go to the second grade.\" \"I hope you enjoyed that as much as I did.\" \"Are you enjoying yourself?\" \"Wheeeeeeeeee!!!!!\" \"Do you expect me to applaud?\">"
  },
