  "YUKS": {
   "name": "YUKS",
   "kind": "global",
   "file": "verbs.zil",
   "line": 2724,
   "value": "<PLTABLE \"Not a chance.\" \"No way. At least not in this reality.\" \"Did you say that just to impress me?\" \"An interesting concept, but beyond this reality.\" \"I'll give you the benefit of the doubt and just ignore that.\" \"A fishy idea...\" \"What a concept!\" \"Not a prayer.\">"
  },
